   332→            onPurchaseSuccess()
   333→            dismiss()
   334→        } else if storeService.purchaseState != .failed("") {
   335→            errorMessage = ErrorMessage(
   336→                title: "Restaurar Compras",
   337→                message: "Nenhuma assinatura ativa encontrada."
