   342→    // MARK: - Helpers
   343→
   344→    private func updateSelectedProduct() {
   345→        let productID: String
   346→        switch (selectedTier, selectedPeriod) {
   347→        case (.pro, .monthly): productID = StoreKitProductID.proMonthly
   348→        case (.pro, .annual): productID = StoreKitProductID.proAnnual
   349→        case (.elite, .monthly): productID = StoreKitProductID.eliteMonthly
   350→        case (.elite, .annual): productID = StoreKitProductID.eliteAnnual
   351→        default: productID = StoreKitProductID.proAnnual
   352→        }
   353→        selectedProduct = storeService.product(id: productID)
   354→    }
   355→
   356→    private func productForCard(tier: SubscriptionTier) -> Product? {
   357→        let id = selectedPeriod == .annual
   358→            ? (tier == .pro ? StoreKitProductID.proAnnual : StoreKitProductID.eliteAnnual)
   359→            : (tier == .pro ? StoreKitProductID.proMonthly : StoreKitProductID.eliteMonthly)
   360→        return storeService.product(id: id)
   361→    }
   362→
   363→    private func monthlyEquivalent(for product: Product, tier: SubscriptionTier) -> String {
   364→        // Annual price / 12 months — show as "R$X,XX/mês"
   365→        guard let price = Double(product.price.description) else { return "" }
   366→        let monthly = price / 12.0
   367→        return String(format: "equivale a R$%.2f/mês", monthly).replacingOccurrences(of: ".", with: ",")
   368→    }
   369→
   370→    private var ctaLabel: String {
