    11→
    12→@MainActor
    13→final class StoreKitEntitlementRepository: EntitlementRepository, @unchecked Sendable {
    14→    private let modelContainer: ModelContainer
    15→    private let storeKitService: StoreKitService
    16→    private var latest: ProEntitlement
    17→    private var streamContinuation: AsyncStream<ProEntitlement>.Continuation?
    18→    private var cancellables = Set<AnyCancellable>()
    19→    
    20→    private lazy var stream: AsyncStream<ProEntitlement> = {
    21→        AsyncStream { continuation in
    22→            continuation.yield(latest)
    23→            continuation.onTermination = { _ in }
    24→            self.streamContinuation = continuation
    25→        }
    26→    }()
    27→
    28→    init(modelContainer: ModelContainer, storeKitService: StoreKitService) {
    29→        self.modelContainer = modelContainer
    30→        self.storeKitService = storeKitService
    31→        
    32→        // Carregar do cache local primeiro (startup rápido)
    33→        if let snapshot = try? Self.fetchSnapshot(from: modelContainer) {
    34→            latest = EntitlementMapper.toDomain(snapshot)
    35→        } else {
    36→            latest = .free
    37→        }
    38→        
    39→        // Observar mudanças no StoreKitService
    40→        setupSubscriptionObserver()
    41→        
    42→        // Verificar status atual do StoreKit em background
    43→        Task {
    44→            await refreshFromStoreKit()
    45→        }
    46→    }
    47→    
    48→    private func setupSubscriptionObserver() {
    49→        Task {
    50→            var previousTier = storeKitService.currentTier
    51→            while !Task.isCancelled {
    52→                let currentTier = await withObservationTracking {
    53→                    storeKitService.currentTier
    54→                } onChange: {
    55→                    // Returns when tier changes
    56→                }
    57→
    58→                if currentTier != previousTier {
    59→                    let entitlement = await storeKitService.getCurrentEntitlement()
    60→                    await updateEntitlement(entitlement)
    61→                    previousTier = currentTier
    62→                }
    63→
    64→                try? await Task.sleep(nanoseconds: 100_000_000) // 100ms
    65→            }
    66→        }
    67→    }
    68→    
    69→    private func refreshFromStoreKit() async {
    70→        await storeKitService.refreshPurchaseStatus()
    71→        let entitlement = await storeKitService.getCurrentEntitlement()
    72→        await updateEntitlement(entitlement)
    73→    }
    74→
    75→    func currentEntitlement() async throws -> ProEntitlement {
    76→        latest
    77→    }
    78→
    79→    func entitlementStream() -> AsyncStream<ProEntitlement> {
    80→        _ = stream
    81→        return stream
    82→    }
    83→    
    84→    private func updateEntitlement(_ entitlement: ProEntitlement) async {
    85→        guard entitlement != latest else { return }
    86→        latest = entitlement
    87→        streamContinuation?.yield(entitlement)
    88→        try? Self.save(snapshot: entitlement, in: modelContainer)
    89→    }
    90→    
    91→    // MARK: - StoreKit Service Access
    92→    
    93→    var service: StoreKitService {
    94→        storeKitService
    95→    }
    96→
    97→    // MARK: - Persistence
    98→
    99→    private static func fetchSnapshot(from container: ModelContainer) throws -> SDProEntitlementSnapshot? {
   100→        let context = ModelContext(container)
   101→        var descriptor = FetchDescriptor<SDProEntitlementSnapshot>()
   102→        descriptor.fetchLimit = 1
   103→        return try context.fetch(descriptor).first
   104→    }
   105→
   106→    private static func save(snapshot entitlement: ProEntitlement, in container: ModelContainer) throws {
   107→        let context = ModelContext(container)
   108→        var descriptor = FetchDescriptor<SDProEntitlementSnapshot>()
   109→        descriptor.fetchLimit = 1
   110→        if let existing = try context.fetch(descriptor).first {
   111→            existing.isPro = entitlement.isPro
   112→            existing.sourceRaw = entitlement.source.rawValue
   113→            existing.expirationDate = entitlement.expirationDate
   114→            existing.updatedAt = Date()
   115→        } else {
   116→            context.insert(EntitlementMapper.toSnapshot(entitlement))
   117→        }
   118→        try context.save()
   119→    }
   120→}
