import SwiftUI
import Swinject

struct AIChatView: View {

    let resolver: Resolver

    @Environment(AppRouter.self) private var router
    @State private var viewModel: AIChatViewModel
    @State private var showClearConfirmation = false

    private var storeKitRepository: StoreKitEntitlementRepository? {
        resolver.resolve(EntitlementRepository.self) as? StoreKitEntitlementRepository
    }

    init(resolver: Resolver) {
        self.resolver = resolver
        self._viewModel = State(initialValue: AIChatViewModel(resolver: resolver))
    }

    var body: some View {
        ZStack {
            FitTodayColor.background.ignoresSafeArea()

            VStack(spacing: 0) {
                if viewModel.messages.isEmpty {
                    emptyStateView
                } else {
                    messagesListView
                }

                inputBar
            }
        }
        .navigationTitle("fitorb.title".localized)
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarTrailing) {
                if !viewModel.messages.isEmpty {
                    Button {
                        showClearConfirmation = true
                    } label: {
                        Image(systemName: "trash")
                            .foregroundStyle(FitTodayColor.textSecondary)
                    }
                }
            }
        }
        .task {
            await viewModel.loadHistory()
        }
        .alert(
            viewModel.errorMessage?.title ?? "",
            isPresented: .init(
                get: { viewModel.errorMessage != nil },
                set: { if !$0 { viewModel.errorMessage = nil } }
            )
        ) {
            Button("OK") { viewModel.errorMessage = nil }
        } message: {
            Text(viewModel.errorMessage?.message ?? "")
        }
        .confirmationDialog(
            "fitorb.clear_chat_confirm".localized,
            isPresented: $showClearConfirmation,
            titleVisibility: .visible
        ) {
            Button("fitorb.clear_chat".localized, role: .destructive) {
                Task { await viewModel.clearHistory() }
            }
        }
        .sheet(isPresented: $viewModel.showPaywall) {
            if let repo = storeKitRepository {
                OptimizedPaywallView(
                    storeService: repo.service,
                    onPurchaseSuccess: {
                        viewModel.showPaywall = false
                    },
                    onDismiss: {
                        viewModel.showPaywall = false
                    }
                )
            }
        }
    }

    // MARK: - Empty State

    private var emptyStateView: some View {
