//  FitToday
//
//  Redesigned on 23/01/26 - New Settings layout with Premium and Apple Health
//

import SwiftUI
import SwiftData
import Swinject

struct ProfileProView: View {
    @Environment(\.dependencyResolver) private var resolver
    @Environment(AppRouter.self) private var router
    @AppStorage(AppStorageKeys.themePreference) private var themePreferenceRaw: String = ThemePreference.dark.rawValue
    @State private var entitlement: ProEntitlement = .free
    @State private var showingPaywall = false
    @State private var showingRestoreAlert = false
    @State private var restoreMessage = ""
    @State private var userName: String = "Athlete"
    @State private var userProfile: UserProfile?
    @State private var streakDays: Int = 0
    @State private var totalMinutes: Int = 0
    @State private var completedWorkouts: Int = 0
    @State private var isPersonalTrainerEnabled = false

    #if DEBUG
    @State private var debugModeEnabled = false
    @State private var debugIsPro = false
    #endif

    private var entitlementRepository: EntitlementRepository? {
        resolver.resolve(EntitlementRepository.self)
    }

    private var storeKitRepository: StoreKitEntitlementRepository? {
        resolver.resolve(EntitlementRepository.self) as? StoreKitEntitlementRepository
    }

    var body: some View {
        ScrollView {
            VStack(spacing: FitTodaySpacing.lg) {
                // User Profile Header
                ProfileHeaderSection(name: userName)

                // Stats Row
                ProfileStatsRow(
                    streak: streakDays,
                    totalMinutes: totalMinutes,
                    completedWorkouts: completedWorkouts
                )

                // Premium Card
                premiumCard

                // Apple Health Integration
                appleHealthCard

                // Personal Trainer
                if isPersonalTrainerEnabled {
                    personalTrainerCard
                }

                // Training Profile
                trainingProfileSection

                // Profile Settings
                settingsSection

                // Account
                accountSection

                #if DEBUG
                DebugSection(
                    debugModeEnabled: $debugModeEnabled,
                    debugIsPro: $debugIsPro,
                    showingRestoreAlert: $showingRestoreAlert,
                    restoreMessage: $restoreMessage,
                    resolver: resolver,
                    onDebugModeChange: handleDebugModeChange,
                    onDebugProChange: handleDebugProChange
                )
                #endif

                AppInfoFooter()
            }
            .padding()
            .padding(.bottom, FitTodaySpacing.xl)
        }
        .background(FitTodayColor.background.ignoresSafeArea())
        .toolbar(.hidden, for: .navigationBar)
        .task {
            await loadEntitlement()
            await loadProfileData()
            if let featureFlags = resolver.resolve(FeatureFlagChecking.self) {
                isPersonalTrainerEnabled = await featureFlags.isFeatureEnabled(.personalTrainerEnabled)
            }
        }
        .sheet(isPresented: $showingPaywall) {
            paywallSheet
        }
        .alert("Restore Purchases", isPresented: $showingRestoreAlert) {
            Button("Ok", role: .cancel) {}
        } message: {
            Text(restoreMessage)
        }
    }

    // MARK: - Header

    private var headerSection: some View {
        VStack(alignment: .leading, spacing: 4) {
            Text("settings.title".localized)
                .font(.system(size: 28, weight: .bold))
                .foregroundStyle(FitTodayColor.textPrimary)
            Text("settings.subtitle".localized)
                .font(.system(size: 14))
                .foregroundStyle(FitTodayColor.textSecondary)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.top, FitTodaySpacing.md)
    }

    // MARK: - Premium Card

    private var premiumCard: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.md) {
            // Badge
            HStack {
                HStack(spacing: 6) {
                    Image(systemName: entitlement.isPro ? "crown.fill" : "sparkles")
                        .font(.system(size: 12, weight: .semibold))
                    Text(entitlement.isPro ? "settings.pro.member".localized : "settings.pro.free".localized)
                        .font(.system(size: 11, weight: .semibold))
                }
                .foregroundStyle(.white)
                .padding(.horizontal, 10)
                .padding(.vertical, 4)
                .background(entitlement.isPro ? FitTodayColor.success : FitTodayColor.brandPrimary)
                .clipShape(Capsule())

                Spacer()
            }

            if entitlement.isPro {
                // Pro content
                Text("settings.pro.title".localized)
                    .font(.system(size: 20, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text("settings.pro.access_all".localized)
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textSecondary)

                // Active features status
                HStack(spacing: FitTodaySpacing.md) {
                    syncStatusItem(icon: "heart.fill", label: "settings.pro.apple_health".localized, isActive: true)
                    syncStatusItem(icon: "bolt.fill", label: "settings.pro.ai_workouts".localized, isActive: true)
                }
                .padding(.top, 4)

                HStack(spacing: 6) {
                    Image(systemName: "checkmark.seal.fill")
                        .font(.system(size: 12, weight: .semibold))
                    Text("settings.pro.subscription_active".localized)
                        .font(.system(size: 14, weight: .semibold))
                }
                .foregroundStyle(FitTodayColor.success)
                .frame(maxWidth: .infinity)
                .padding(.vertical, 12)
                .background(FitTodayColor.success.opacity(0.15))
                .clipShape(RoundedRectangle(cornerRadius: 12))
            } else {
                // Free plan upgrade prompt
                Text("settings.pro.upgrade".localized)
                    .font(.system(size: 20, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text("settings.pro.unlock_description".localized)
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textSecondary)

                // Features preview
                VStack(alignment: .leading, spacing: 8) {
                    featureItem(icon: "sparkles", text: "settings.pro.unlimited_ai".localized)
                    featureItem(icon: "chart.bar.fill", text: "settings.pro.advanced_charts".localized)
                    featureItem(icon: "heart.fill", text: "settings.pro.health_integration".localized)
                }
                .padding(.top, 4)

                Button {
                    showingPaywall = true
                } label: {
                    HStack {
                        Spacer()
